WHERE 1 = 1 AND EXISTS (SELECT * FROM PA_SUPERVISOR_INFO WHERE PA_SUPERVISOR_INFO.DEPTNO = he.DEPTNO AND PA_SUPERVISOR_INFO.PERSON_ID = #{adminID, jdbcType=VARCHAR})
AND (he.EMPID LIKE '%' || #{empSearch, jdbcType=VARCHAR} || '%' OR CONVERTTOUNSIGN(UPPER(he.LOCAL_NAME)) LIKE '%' || CONVERTTOUNSIGN(UPPER(#{empSearch, jdbcType=VARCHAR})) || '%')
AND he.DEPTNO IN
#{d, jdbcType=VARCHAR}
AND he.EMP_OFFICE = #{empOfficeSearch, jdbcType=VARCHAR}
AND pea.ACCOUNT_TYPE = #{bankSearch, jdbcType=VARCHAR}
AND he.DATE_STARTED >= TO_DATE(#{fromDateStarted, jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND he.DATE_STARTED <= TO_DATE(#{toDateStarted, jdbcType=VARCHAR}, 'YYYY-MM-DD')
